{
  name: "get_flaky_tests",
  description: `Get list of flaky tests sorted by flakiness rate. A test is flaky if it sometimes passes after retries.

Fields returned per test:
- test_signature: string - Unique test identifier
- test_name: string - Test title
- test_file: string - Spec file path
- flakiness_rate: number - Percentage of runs that required retries (0-100)
- total_runs: number - Total executions
- flaky_runs: number - Runs with retry
- last_flaky: ISO datetime`,
  inputSchema: {
    type: "object" as const,
    properties: {
      limit: { type: "number", description: "Max results", default: 10 },
      min_runs: { type: "number", description: "Minimum runs to be considered", default: 5 },
    },
  },
}

case "get_flaky_tests": {
  const input = z.object({
    limit: z.number().min(1).max(100).default(10),
    min_runs: z.number().min(1).default(5),
  }).parse(args)

  const flakyTests = await db.getFlakiestTests(orgId, input.limit, input.min_runs)

  return jsonResponse({
    organization: authContext.organizationSlug,
    count: flakyTests.length,
    flaky_tests: flakyTests,
  })
}

export async function getFlakiestTests(
  organizationId: number,
  limit: number = 10,
  minRuns: number = 5
): Promise<TestFlakinessHistory[]> {
  const sql = getSql()

  const results = await sql`
    SELECT *
    FROM test_flakiness_history
    WHERE total_runs >= ${minRuns}
      AND flaky_runs > 0
      AND organization_id = ${organizationId}
    ORDER BY flakiness_rate DESC, flaky_runs DESC
    LIMIT ${limit}
  `

  return results as TestFlakinessHistory[]
}

solution.updated_db_function:
export async function getFlakiestTests(
  organizationId: number,
  options: GetFlakiestTestsOptions = {}
): Promise<TestFlakinessHistory[]> {
  const sql = getSql()
  const { 
    limit = 10, 
    minRuns = 5, 
    since, 
    branch, 
    includeResolved = false 
  } = options

  const conditions = [
    `organization_id = ${organizationId}`,
    `total_runs >= ${minRuns}`,
  ]

  // Include or exclude resolved tests
  if (!includeResolved) {
    conditions.push("flaky_runs > 0")
  }

  // Time window filter
  if (since) {
    conditions.push(`last_flaky_at >= '${since}'`)
  }

  // Branch filter - requires subquery to check test_results
  let branchFilter = ""
  if (branch) {
    branchFilter = `
      AND test_signature IN (
        SELECT DISTINCT tr.test_signature
        FROM test_results tr
        JOIN test_executions te ON tr.execution_id = te.id
        WHERE te.branch = '${branch}'
          AND te.organization_id = ${organizationId}
          AND tr.is_flaky = true
      )
    `
  }

  const whereClause = `WHERE ${conditions.join(" AND ")} ${branchFilter}`

  const query = `
    SELECT 
      tfh.*,
      (
        SELECT te.branch 
        FROM test_results tr 
        JOIN test_executions te ON tr.execution_id = te.id
        WHERE tr.test_signature = tfh.test_signature
          AND tr.is_flaky = true
          AND te.organization_id = ${organizationId}
        ORDER BY tr.started_at DESC
        LIMIT 1
      ) as last_flaky_branch
    FROM test_flakiness_history tfh
    ${whereClause}
    ORDER BY flakiness_rate DESC, flaky_runs DESC
    LIMIT ${limit}
  `

  const results = await sql.unsafe(query)
  return results as TestFlakinessHistory[]
}

solution.updated_tool_definition:
{
  name: "get_flaky_tests",
  description: `Get list of flaky tests sorted by flakiness rate. A test is flaky if it sometimes passes after retries.

Supports filtering by time window, branch, and resolution status.

Fields returned per test:
- test_signature: string - Unique test identifier
- test_name: string - Test title
- test_file: string - Spec file path
- flakiness_rate: number - Percentage of runs that required retries (0-100)
- total_runs: number - Total executions
- flaky_runs: number - Runs with retry
- last_flaky: ISO datetime - When test was last flaky
- last_flaky_branch: string | null - Branch where test was last flaky`,
  inputSchema: {
    type: "object" as const,
    properties: {
      limit: { 
        type: "number", 
        description: "Max results", 
        default: 10 
      },
      min_runs: { 
        type: "number", 
        description: "Minimum runs to be considered", 
        default: 5 
      },
      since: { 
        type: "string", 
        description: "Only include tests that have been flaky since this date (ISO 8601)" 
      },
      branch: { 
        type: "string", 
        description: "Filter to tests that are flaky on this specific branch" 
      },
      include_resolved: { 
        type: "boolean", 
        default: false,
        description: "Include tests that are no longer flaky (flaky_runs = 0)" 
      },
    },
  },
}

solution.updated_handler:
case "get_flaky_tests": {
  const input = z.object({
    limit: z.number().min(1).max(100).default(10),
    min_runs: z.number().min(1).default(5),
    since: z.string().optional(),
    branch: z.string().optional(),
    include_resolved: z.boolean().default(false),
  }).parse(args)

  const flakyTests = await db.getFlakiestTests(orgId, {
    limit: input.limit,
    minRuns: input.min_runs,
    since: input.since,
    branch: input.branch,
    includeResolved: input.include_resolved,
  })

  return jsonResponse({
    organization: authContext.organizationSlug,
    filters: {
      since: input.since || "all time",
      branch: input.branch || "all",
      include_resolved: input.include_resolved,
    },
    count: flakyTests.length,
    flaky_tests: flakyTests,
  })
}
